// 메이크샵 상품 목록 파싱 + 카테고리/키워드 자동 추출
var raw = $input.first().json;
var body = typeof raw === 'string' ? raw : (raw.body || JSON.stringify(raw));

var data;
try { data = JSON.parse(body); } catch(e) {
  throw new Error('메이크샵 API 응답 파싱 실패. 응답: ' + String(body).slice(0, 300));
}

if (data && data.return_code && data.return_code !== '0000') {
  throw new Error('메이크샵 API 오류 ' + data.return_code + ': ' + JSON.stringify(data).slice(0, 200) + ' → 어드민 오픈API 조회 권한 확인 필요');
}

var CATEGORY_KEYWORDS = {
  '압화': ['압화', '프레스드플라워', '프레스드', '건조꽃', '드라이플라워', '하바리움', '부케', '꽃'],
  '레진': ['레진', 'UV레진', '에폭시', '실리콘몰드', '몰드', '레지너스', '꽃레진'],
  '캔들': ['캔들', '왁스', '소이왁스', '향초', '심지'],
  '석고': ['석고', '방향제', '아로마'],
  '비즈': ['비즈', '구슬', '클레이']
};

function detectCategory(name) {
  if (!name) return '';
  var lname = name.toLowerCase();
  for (var cat in CATEGORY_KEYWORDS) {
    var words = CATEGORY_KEYWORDS[cat];
    for (var i = 0; i < words.length; i++) {
      if (lname.indexOf(words[i]) >= 0) return cat;
    }
  }
  return '';
}

function extractKeywords(name) {
  if (!name) return [];
  var kws = [];
  var lname = name.toLowerCase();
  for (var cat in CATEGORY_KEYWORDS) {
    var words = CATEGORY_KEYWORDS[cat];
    for (var i = 0; i < words.length; i++) {
      if (lname.indexOf(words[i]) >= 0 && kws.indexOf(words[i]) < 0) kws.push(words[i]);
    }
  }
  // 키워드 없으면 상품명 첫 단어로 폴백
  if (kws.length === 0 && name) kws.push(name.split('/')[0].split(' ')[0].trim());
  return kws;
}

var rawList = [];
if (data && data.datas && Array.isArray(data.datas)) rawList = data.datas;
else if (Array.isArray(data)) rawList = data;

var records = [];
for (var j = 0; j < rawList.length; j++) {
  var p = rawList[j];
  // 메이크샵 API 필드명 (실제 응답 확인 후 조정 가능)
  var branduid = String(p.branduid || p.uid || p.product_id || '');
  var name = p.product_name || p.name || '';
  var price = parseInt(p.sellprice || p.price || 0);
  var image = p.image1 || p.mainimage || p.image || '';
  if (image && !image.startsWith('http')) image = 'https://foreverlove.co.kr' + image;

  if (branduid && name) {
    records.push({
      branduid: branduid,
      product_name: name,
      price: isNaN(price) ? 0 : price,
      image_url: image,
      product_url: 'https://foreverlove.co.kr/shop/shopdetail.html?branduid=' + branduid,
      category_name: detectCategory(name),
      keywords: JSON.stringify(extractKeywords(name)),
      status: 'active',
      synced_at: new Date().toISOString()
    });
  }
}

if (records.length === 0) {
  throw new Error('파싱된 상품이 없습니다. API 응답: ' + JSON.stringify(data).slice(0, 500));
}

return [{ json: { products: records, total: records.length } }];

var parsed = $('Parse Products').first().json;
var existingResp = $input.first().json;

var newProducts = parsed.products || [];
var existing = (existingResp && existingResp.list) ? existingResp.list : [];

var existingMap = {};
for (var i = 0; i < existing.length; i++) {
  existingMap[String(existing[i].branduid)] = { id: existing[i].Id, price: existing[i].price };
}

var toInsert = [];
var toUpdate = [];

for (var j = 0; j < newProducts.length; j++) {
  var p = newProducts[j];
  var ex = existingMap[String(p.branduid)];
  if (ex) {
    // 가격 변경 시만 업데이트
    if (parseInt(ex.price) !== parseInt(p.price)) {
      toUpdate.push({ Id: ex.id, price: p.price, image_url: p.image_url, synced_at: p.synced_at });
    }
  } else {
    toInsert.push(p);
  }
}

return [{ json: { toInsert: toInsert, toUpdate: toUpdate, insertCount: toInsert.length, updateCount: toUpdate.length } }];

var d = $('Upsert Decision').first().json;
var now = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });
var msg = '📦 메이크샵 상품 카탁로그 동기화 완료\n신규: ' + (d.insertCount||0) + '개\n갱신: ' + (d.updateCount||0) + '개\n시간: ' + now;
return [{ json: { message: msg, insertCount: d.insertCount, updateCount: d.updateCount } }];
